public static String getStackTrace(final Throwable throwable) {
        final StringWriter sw = new StringWriter();
        final PrintWriter pw = new PrintWriter(sw, true);
        if (throwable != null) {
            throwable.printStackTrace(pw);
        }
        return sw.getBuffer().toString();
    }
